head.script:
//-------------------------------------------------------------------------
// 호출 화면으로 전달받는 파라미터 전역변수 선언, 현재는 읽어들일수 없어서 모화면과 연결시 주석 해제
//-------------------------------------------------------------------------
scwin.param = "";
scwin.check = "";
scwin.args = "";
scwin.jsonParam = "";

// 더미용 데이터
scwin.odrNo           = "";
scwin.lunionOrgCd     = "";
scwin.wrkDt           = "";
scwin.stvWrkIndictNo  = "";
scwin.expClsCd        = "";
scwin.shiftCd         = "";
scwin.lunionPartySeq  = "";
scwin.wrkPlNm         = "";
scwin.cvsslMgntNo     = "";
scwin.processChk      = "";
scwin.wrkPlCd         = "";
scwin.holdNo 			= "";
scwin.checkRow        = 0;
scwin.flag            = 0;
scwin.totalRows       = 0;
scwin.rtnValues = [];
scwin.closeArr = [];

// 호출 화면 파라미터 op_307_01_29b

// var args = new Array();
// args[0] = ds_retrieveResultNew.getCellData(ds_retrieveResultNew.getRowPosition(), "odrNo");
// args[1] = ds_retrieveResultNew.getCellData(ds_retrieveResultNew.getRowPosition(), "lunionOrgCd");
// args[2] = ds_retrieveResultNew.getCellData(ds_retrieveResultNew.getRowPosition(), "wrkDt");
// args[4] = ds_retrieveResultNew.getCellData(ds_retrieveResultNew.getRowPosition(), "impExpClsCd");
// args[5] = ds_retrieveResultNew.getCellData(ds_retrieveResultNew.getRowPosition(), "shiftClsCd");
// args[7] = ds_main1.getCellData(0, "wrkPlNm"); //TOBE : ds_main1 선언 없는 데이터리스트
// args[8] = ds_main1.getCellData(0, "cvsslMgntNo");
// args[12] = 0;

//-------------------------------------------------------------------------
// 페이지 로드
//-------------------------------------------------------------------------
scwin.onpageload = function() {

scwin.args = $p.getAllParameter().paramData.data;
scwin.param = $c.data.getParameter();
scwin.check = scwin.param.check == null ? "" : scwin.param.check;



scwin.odrNo           = scwin.args[0] == null ? "" : scwin.args[0];
scwin.lunionOrgCd     = scwin.args[1] == null ? "" : scwin.args[1];
scwin.wrkDt           = scwin.args[2] == null ? "" : scwin.args[2];
scwin.stvWrkIndictNo  = scwin.args[3] == null ? "" : scwin.args[3];
scwin.expClsCd        = scwin.args[4] == null ? "" : scwin.args[4];
scwin.shiftCd         = scwin.args[5] == null ? "" : scwin.args[5];
scwin.lunionPartySeq  = scwin.args[6] == null ? "" : scwin.args[6];
scwin.wrkPlNm         = scwin.args[7] == null ? "" : scwin.args[7];
scwin.cvsslMgntNo     = scwin.args[8] == null ? "" : scwin.args[8];
scwin.processChk      = scwin.args[10] == null ? "" : scwin.args[10];
scwin.wrkPlCd         = scwin.args[11] == null ? "" : scwin.args[11];
scwin.holdNo 		  = scwin.args[12] == null ? "" : scwin.args[12];



    // 전역변수로 받은 파라미터 사용
    if(scwin.check != "T") {
	    ed_portName.setValue(scwin.wrkPlNm);
        ed_shipNumber.setValue(scwin.cvsslMgntNo);
    };

    dma_condition.set("args", scwin.args);
    dma_condition.set("odrNo", scwin.odrNo);
    dma_condition.set("lunionOrgCd", scwin.lunionOrgCd);
    dma_condition.set("wrkDt",scwin.wrkDt);
    dma_condition.set("stvWrkIndictNo",scwin.stvWrkIndictNo );
    dma_condition.set("expClsCd", scwin.expClsCd);
    dma_condition.set("shiftCd", scwin.shiftCd);
    dma_condition.set("cvsslMgntNo" ,scwin.cvsslMgntNo);
    dma_condition.set("wrkPlCd", scwin.wrkPlCd);
    dma_condition.set("holdNo", scwin.holdNo);
    dma_condition.set("partyLunionOrgCd", "");

    if(scwin.lunionPartySeq > 0){
        dma_condition.set("lunionPartySeq", scwin.lunionPartySeq);
    } else {
        dma_condition.set("lunionPartySeq", "");
    };

    scwin.f_RetrieveDetail();
};


scwin.f_checkStaffNo = function(rowCnt) {
    scwin.totalRows = rowCnt;

    for (i=0; i < rowCnt; i++) {
        let chiefYn = ds_retrieveResult.getCellData(i, "chiefYn");
        if ( "1" == chiefYn ) {
            ds_retrieveResult.setCellData(i, "chk", 1);
        }
    }
}




//-------------------------------------------------------------------------
// 반장 그리드 셀 선택시
//-------------------------------------------------------------------------
scwin.gr_master_onClick = function (rowIndex, columnIndex, columnId) {
    dma_condition.set("holdNo", scwin.holdNo);
    dma_condition.set("partyLunionOrgCd", ds_master.getCellData(rowIndex, "partyLunionOrgCd"))

    $c.sbm.execute(sbm_retrieve);
};


//-------------------------------------------------------------------------
// 반원 그리드내에 cell 선택시
//-------------------------------------------------------------------------
scwin.gr_retrieveResult_onClick = function (rowIndex, columnIndex, columnId) {
    let checkId = columnId;
    let chk = ds_retrieveResult.getCellData(rowIndex, "chk");
    ds_chkResult.removeAll();

    if(columnId == "chk" && chk == "1"){
        dma_chk.set("odrNo", scwin.odrNo);  //오더번호
        dma_chk.set("wrkDt", scwin.wrkDt);  //작업일자
        dma_chk.set("wrkPlCd", scwin.wrkPlCd); //작업장코드
        dma_chk.set("staffNo", ds_retrieveResult.getCellData(rowIndex, "staffNo")); //사번
		dma_chk.set("shiftCd", scwin.shiftCd); 
		dma_chk.set("cvsslMgntNo", scwin.cvsslMgntNo);
		dma_chk.set("expClsCd", scwin.expClsCd);
		dma_chk.set("lunionOrgCd", scwin.lunionOrgCd);
		dma_chk.set("holdNo", scwin.holdNo);


        let row = ds_chkResult.insertRow();
        ds_chkResult.setCellData(row, "chk", "0");

        scwin.f_RetrieveChk();
        // scwin.f_rowsDisplay();
    }

    scwin.f_rowsDisplay();
};


//-------------------------------------------------------------------------
// 반원 그리드내에 cell 선택시 총 인원 노출
//-------------------------------------------------------------------------
scwin.f_rowsDisplay = function() {

        let row    = ds_retrieveResult.getTotalRow();
        let chkRow = 0;
        let text   = "선택인원 : ";

        if(ds_retrieveResult.getRowPosition() >= 0) {
	        for(i = 0; i < row; i++) {
	            let chk     = ds_retrieveResult.getCellData(i, "chk");
	            let chiefYn = ds_retrieveResult.getCellData(i, "chiefYn");
	            if ( chk == 1 ) chkRow++;
	            /*if ( "1" == chiefYn && chk == 0 ) {
	                //cfAlertMsg("반장은 필수 선택입니다.");
	                ds_retrieveResult.NameValue(i, "chk") = 1;
	            }*/
	        }
        }
        totalInfo = text+chkRow;
        ed_showChkRow.setValue(totalInfo);

        scwin.checkRow = chkRow;
        scwin.totalRows = row;
    }


//-------------------------------------------------------------------------
// 반원 그리드 헤더 체크박스 셀 선택시 (웹스퀘어 자동)
//-------------------------------------------------------------------------
scwin.gr_retrieveResult_onHeaderClick = function (headerId) {
    scwin.f_rowsDisplay();
};


//-------------------------------------------------------------------------
// 조회 --HoldNo를 화면에서 받아오기에 사용하지 않을 예정..  by hanchoice
//-------------------------------------------------------------------------
scwin.f_RetrieveDetail = function() {

    dma_condition.set("holdNo", scwin.holdNo);    

    $c.sbm.execute(sbm_retrieveMaster);
}


scwin.sbm_retrieveMaster_submitDone = function (rowCnt) {
    if(rowCnt > 0) {
        dma_condition.set("holdNo", holdNo);
        dma_condition.set("partyLunionOrgCd", ds_master.get("partyLunionOrgCd"));

    }    
    $c.sbm.execute(sbm_retrieve);
};



//-------------------------------------------------------------------------
// 저장버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_allCheck = function() {
    let rowCnt = ds_retrieveResult.getTotalRow();
    if ( flag == 0 ) {
        for (i=1; i<=rowCnt; i++) {
            ds_retrieveResult.setCellData(i, "chk", 1);
        }
        flag = 1;
    }
    else if ( flag == 1 ) {
        for (i=1; i<=rowCnt; i++) {
            ds_retrieveResult.setCellData(i,"chk", 0);
        }
        flag = 0;
    }

    scwin.f_checkStaffNo(rowCnt);    
    scwin.f_rowsDisplay();

}



//-------------------------------------------------------------------------
// 투입반원 중복 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveChk = function() {
    $c.sbm.execute(sbm_chkRetrieve);
}




//-------------------------------------------------------------------------
// 저장버튼 클릭시
//-------------------------------------------------------------------------
scwin.btn_save_onClick = function (e) {
    let row = ds_retrieveResult.getRowCount();

    // 84번 line은 공백으로 넘어가는 쿼리 제한하기 위함
    // if(row < 1) return;

    for(i = 0; i < row; i++){
        let status = ds_retrieveResult.getRowStatus(i);
        if(status != "R" && ds_retrieveResult.getCellData(i, "chk") == "0") {
            ds_retrieveResult.modifyRowStatus(i, "D");
        }
    }

    $c.sbm.execute(sbm_save);


};
//-------------------------------------------------------------------------
// 저장 성공
//-------------------------------------------------------------------------
scwin.sbm_save_submitDone = async function (e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0)return; //onFail
        $c.win.alert(MSG_CM_INF_001);
        // 관련 내용 하단 기재
        scwin.f_RetrieveDetail();

        let row = ds_retrieveResult.getRowCount();
        if(row == 0) return;

        scwin.rtnValues[0] = scwin.checkRow;
        scwin.rtnValues[1] = scwin.totalRows;
        // $p.parent().scwin.closeArr = scwin.rtnValues;

    } catch (e) {
       console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
    }

};

// 닫기
scwin.btn_close_onClick = function (e) {
    $c.win.closePopup(scwin.rtnValues);
};

// 취소
scwin.btn_cancle_onClick = function (e) {
    ds_retrieveResult.undoAll();  
};

//-------------------------------------------------------------------------
// 반장 데이터 로드시
//-------------------------------------------------------------------------
scwin.ds_master_ondataload = function () {
    let rowCnt = ds_master.getRowCount();

    if(rowCnt > 0) {
        dma_condition.set("holdNo", scwin.holdNo);
        dma_condition.set("partyLunionOrgCd", ds_master.getCellData(0, "partyLunionOrgCd"));
        $c.sbm.execute(sbm_retrieve);

    }

    spa_totalRows1.setValue(rowCnt);

    gr_master.setFocusedCell(0, 0);
};

//-------------------------------------------------------------------------
// 반원 데이터 로드시
//-------------------------------------------------------------------------
scwin.ds_retrieveResult_ondataload = function () {
    let rowCnt = ds_retrieveResult.getRowCount();

    spa_totalRows2.setValue(rowCnt);
    gr_retrieveResult.setFocusedCell(0, 1);

};


//-------------------------------------------------------------------------
// 중복 체크 
//-------------------------------------------------------------------------
scwin.ds_chkResult_ondataload = function () {
    let row = ds_chkResult.getRowCount();
    chk = ds_chkResult.getCellData((row-1), "chk");

    if(chk > 0) {
        $c.win.alert("다른 작업장에 등록된 인원 입니다.");
    }


};
